import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { getProductById, createProduct, updateProduct } from '../../../services/productService';

const ProductForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    price: '',
    originalPrice: '',
    discount: 0,
    brand: '',
    category: 'Cooling Pads',
    stock: '',
    sku: '',
    images: [],
    warranty: 'No warranty',
    compatibility: []
  });

  const categories = [
    'Cooling Pads',
    'Water Pumps',
    'Motors',
    'Fans & Blowers',
    'Remote Controls',
    'Castor Wheels',
    'Filters',
    'Water Level Indicators',
    'Switches & Buttons',
    'Cooler Bodies',
    'Ice Chambers',
    'Other Parts'
  ];

  useEffect(() => {
    if (id) {
      loadProduct();
    }
  }, [id]);

  const loadProduct = async () => {
    try {
      setLoading(true);
      const res = await getProductById(id);
      const product = res.data;
      setFormData({
        name: product.name,
        description: product.description,
        price: product.price,
        originalPrice: product.originalPrice || '',
        discount: product.discount || 0,
        brand: product.brand || '',
        category: product.category,
        stock: product.stock || product.countInStock || '',
        sku: product.sku || '',
        images: product.images || [],
        warranty: product.warranty || 'No warranty',
        compatibility: product.compatibility || []
      });
    } catch (err) {
      toast.error('Failed to load product');
      navigate('/admin/products');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'price' || name === 'stock' || name === 'discount' || name === 'originalPrice' 
        ? parseFloat(value) || '' 
        : value
    }));
  };

  const handleImagesChange = (e) => {
    const value = e.target.value;
    setFormData(prev => ({
      ...prev,
      images: value.split(',').map(img => img.trim()).filter(img => img)
    }));
  };

  const handleCompatibilityChange = (e) => {
    const value = e.target.value;
    setFormData(prev => ({
      ...prev,
      compatibility: value.split(',').map(c => c.trim()).filter(c => c)
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.description || !formData.price || !formData.category || formData.stock === '') {
      toast.error('Please fill in all required fields');
      return;
    }

    try {
      setLoading(true);
      if (id) {
        await updateProduct(id, formData);
        toast.success('Product updated');
      } else {
        await createProduct(formData);
        toast.success('Product created');
      }
      navigate('/admin/products');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save product');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <h1>{id ? 'Edit Product' : 'Create Product'}</h1>

      <div className="card mt-2">
        {loading && id ? (
          <div className="loader" />
        ) : (
          <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Product Name *</label>
            <input
              type="text"
              name="name"
              className="form-control"
              value={formData.name}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label className="form-label">Description *</label>
            <textarea
              name="description"
              className="form-control"
              rows="4"
              value={formData.description}
              onChange={handleChange}
              required
              style={{ resize: 'vertical' }}
            />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
            <div className="form-group">
              <label className="form-label">Category *</label>
              <select
                name="category"
                className="form-control"
                value={formData.category}
                onChange={handleChange}
                required
              >
                {categories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Brand</label>
              <input
                type="text"
                name="brand"
                className="form-control"
                value={formData.brand}
                onChange={handleChange}
              />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: '20px' }}>
            <div className="form-group">
              <label className="form-label">Price (₹) *</label>
              <input
                type="number"
                name="price"
                className="form-control"
                value={formData.price}
                onChange={handleChange}
                step="0.01"
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label">Original Price (₹)</label>
              <input
                type="number"
                name="originalPrice"
                className="form-control"
                value={formData.originalPrice}
                onChange={handleChange}
                step="0.01"
              />
            </div>

            <div className="form-group">
              <label className="form-label">Discount (%)</label>
              <input
                type="number"
                name="discount"
                className="form-control"
                value={formData.discount}
                onChange={handleChange}
                min="0"
                max="100"
              />
            </div>

            <div className="form-group">
              <label className="form-label">Stock *</label>
              <input
                type="number"
                name="stock"
                className="form-control"
                value={formData.stock}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">SKU</label>
            <input
              type="text"
              name="sku"
              className="form-control"
              value={formData.sku}
              onChange={handleChange}
              placeholder="e.g., CP-001"
            />
          </div>

          <div className="form-group">
            <label className="form-label">Image URLs (comma separated)</label>
            <textarea
              name="images"
              className="form-control"
              rows="2"
              value={formData.images.join(', ')}
              onChange={handleImagesChange}
              placeholder="https://example.com/image1.jpg, https://example.com/image2.jpg"
              style={{ resize: 'vertical' }}
            />
          </div>

          <div className="form-group">
            <label className="form-label">Warranty</label>
            <input
              type="text"
              name="warranty"
              className="form-control"
              value={formData.warranty}
              onChange={handleChange}
              placeholder="e.g., 1 Year Warranty"
            />
          </div>

          <div className="form-group">
            <label className="form-label">Compatibility (comma separated)</label>
            <textarea
              name="compatibility"
              className="form-control"
              rows="2"
              value={formData.compatibility.join(', ')}
              onChange={handleCompatibilityChange}
              placeholder="Compatible models separated by commas"
              style={{ resize: 'vertical' }}
            />
          </div>

          <div style={{ display: 'flex', gap: '10px' }}>
            <button
              type="submit"
              className="btn btn-primary"
              disabled={loading}
            >
              {loading ? 'Saving...' : id ? 'Update Product' : 'Create Product'}
            </button>
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => navigate('/admin/products')}
              disabled={loading}
            >
              Cancel
            </button>
          </div>
        </form>
        )}
      </div>
    </div>
  );
};

export default ProductForm;
